import java.io.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class SecureCode {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String name = br.readLine();

        // Sanitize user input to prevent XSS attacks
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String sanitizedName = codec.encodeForHTML(name);

        System.out.println("Hello, " + sanitizedName + "!");

        // XSS-safe output using proper encoding
        System.out.println("<script>alert('XSS attack by " + sanitizedName + "');</script>");
    }
}

